import { useState, useMemo } from "react";
import { useLocation, Link } from "react-router-dom";
import { motion } from "framer-motion";
import { Home, Search, Compass, Heart, BarChart3, Scale, Store, ArrowUpRight } from "lucide-react";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { Reveal, fadeUp, stagger } from "@/components/landing/motion";

const suggestions = [
  { to: "/", label: "Home", desc: "Back to the overview", icon: Home },
  { to: "/listings", label: "Listings", desc: "Browse all items", icon: Search },
  { to: "/lookup", label: "Lookup", desc: "Search for an item", icon: Search },
  { to: "/favorites", label: "Favorites", desc: "Your watchlist", icon: Heart },
  { to: "/dashboard", label: "Dashboard", desc: "Market dashboard", icon: BarChart3 },
  { to: "/compare", label: "Compare", desc: "Compare items side by side", icon: Scale },
  { to: "/shops", label: "Shops", desc: "Browse chest shops", icon: Store },
];

const validPrefixes = ["/item/", "/seller/", "/sellers/", "/listings", "/shops", "/lookup", "/favorites", "/compare", "/alerts", "/dashboard", "/trading-history", "/settings", "/legal"];

export default function NotFoundPage() {
  const location = useLocation();
  const [searchVal, setSearchVal] = useState("");
  const isInternalRef = useMemo(() => typeof document !== "undefined" && document.referrer?.startsWith(window.location.origin), []);

  const autoRedirect = useMemo(() => {
    const path = location.pathname;
    for (const prefix of validPrefixes) {
      if (path.startsWith(prefix) && path.length > prefix.length) {
        return prefix;
      }
    }
    return null;
  }, [location.pathname]);

  return (
    <div data-testid="notfound-page" className="min-h-screen bg-bg-base text-white font-body">
      <Header />
      <main className="min-h-[calc(100vh-4rem)] flex items-center justify-center py-24">
        <div className="max-w-2xl mx-auto px-6 text-center">
          {/* Watermark 404 */}
          <div className="relative">
            <div className="text-[10rem] sm:text-[14rem] font-heading font-black leading-[0.8] text-foreground/5 select-none pointer-events-none">
              404
            </div>
            <div className="absolute inset-0 flex items-center justify-center">
              <Reveal>
                <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-amber-400 mb-3 inline-flex items-center gap-2">
                  <Compass className="w-3 h-3" /> Off the map
                </div>
                <h1 className="font-heading text-4xl sm:text-5xl tracking-tighter font-black leading-[1.05] mb-4">
                  Page not found
                </h1>
                <p className="text-zinc-400 max-w-md mx-auto text-base leading-relaxed mb-6">
                  {isInternalRef
                    ? "The link you clicked may be broken or the page has moved."
                    : "The page you're looking for doesn't exist or has been moved."}
                </p>
              </Reveal>
            </div>
          </div>

          {/* Auto-redirect suggestion */}
          {autoRedirect && (
            <Reveal delay={0.1}>
              <Link
                to={location.pathname}
                className="inline-flex items-center gap-2 bg-white/[0.04] border border-amber-500/20 hover:border-amber-500/40 rounded-xl px-5 py-3 text-sm text-zinc-300 hover:text-white transition-colors mb-8"
              >
                <ArrowUpRight className="w-4 h-4 text-amber-400" />
                Did you mean to visit a <strong className="text-white mx-1">{autoRedirect}</strong> page?
              </Link>
            </Reveal>
          )}

          {/* Suggestion cards */}
          <motion.div
            variants={stagger}
            initial="hidden"
            animate="show"
            className="grid grid-cols-2 sm:grid-cols-4 gap-3 mt-6"
          >
            {suggestions.map((s) => (
              <motion.div key={s.to} variants={fadeUp}>
                <Link
                  to={s.to}
                  className="flex flex-col items-center gap-2 bg-white/[0.02] border border-white/10 hover:border-emerald-500/30 hover:bg-white/[0.04] rounded-xl p-4 transition-all group"
                >
                  <s.icon className="w-5 h-5 text-zinc-500 group-hover:text-emerald-400 transition-colors" />
                  <div className="text-xs font-mono font-bold text-zinc-300 group-hover:text-white transition-colors">{s.label}</div>
                  <div className="text-[9px] text-zinc-600">{s.desc}</div>
                </Link>
              </motion.div>
            ))}
          </motion.div>

          {/* Search fallback */}
          <Reveal delay={0.2} className="mt-10">
            <div className="max-w-sm mx-auto">
              <p className="text-[11px] text-zinc-500 mb-2 font-mono uppercase tracking-wider">Were you looking for something?</p>
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-500 pointer-events-none" />
                <input
                  type="text"
                  value={searchVal}
                  onChange={(e) => setSearchVal(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === "Enter" && searchVal.trim()) {
                      window.location.href = `/lookup?q=${encodeURIComponent(searchVal.trim())}`;
                    }
                  }}
                  placeholder="Type to search items…"
                  className="w-full bg-white/[0.04] border border-white/10 rounded-lg pl-10 pr-4 py-2.5 text-sm text-white placeholder:text-zinc-600 focus:outline-none focus:border-emerald-500/50 transition-colors"
                />
              </div>
            </div>
          </Reveal>
        </div>
      </main>
      <Footer />
    </div>
  );
}
